let lastRequestId = 0;
let userData;

function fetchUserData() {
  const currentRequestId = ++lastRequestId;

  fetch('/api/user')
    .then(response => response.json())
    .then(data => {
      if (currentRequestId === lastRequestId) {
        userData = data;
        console.log('User data updated:', userData);
      } else {
        console.log('Discarded outdated response');
      }
    });
}

// Call fetchUserData multiple times, only latest response is used
fetchUserData();
fetchUserData();

async function fetchFastestUserData() {
  const fetch1 = fetch('/api/user').then(res => res.json());
  const fetch2 = fetch('/backup-api/user').then(res => res.json());

  try {
    const userData = await Promise.race([fetch1, fetch2]);
    console.log('Fastest user data:', userData);
  } catch (err) {
    console.error('Fetch failed:', err);
  }
}

fetchFastestUserData();

type Task = {
  id: number;
  description: string;
  completed: boolean;
};

let tasks: Task[] = [];

function addTask(description: string): void {
  const newTask: Task = {
    id: tasks.length + 1,
    description: description,
    completed: false
  };
  tasks.push(newTask);
  console.log(`Task added: ${description}`);
}

function listTasks(): void {
  if (tasks.length === 0) {
    console.log("No tasks yet!");
    return;
  }
  console.log("Current Tasks:");
  tasks.forEach(task => {
    const status = task.completed ? "✔" : "✘";
    console.log(`${task.id}. [${status}] ${task.description}`);
  });
}

function completeTask(id: number): void {
  const task = tasks.find(t => t.id === id);
  if (task) {
    task.completed = true;
    console.log(`Task completed: ${task.description}`);
  } else {
    console.log(`Task with ID ${id} not found.`);
  }
}

function removeTask(id: number): void {
  const index = tasks.findIndex(t => t.id === id);
  if (index !== -1) {
    const removed = tasks.splice(index, 1)[0];
    console.log(`Task removed: ${removed.description}`);
  } else {
    console.log(`Task with ID ${id} not found.`);
  }
}

addTask("Learn TypeScript basics");
addTask("Build a simple To-Do app");
listTasks();
completeTask(1);
listTasks();
removeTask(2);
listTasks();

